    const _host: []const u8 = if (_u.host) |h| switch (h) {
        .raw => |r| r, .percent_encoded => |p| p,
    } else "";
    const _path: []const u8 = switch (_u.path) {
        .raw => |r| r, .percent_encoded => |p| p,
    };
    const _query: []const u8 = if (_u.query) |q| switch (q) {
        .raw => |r| r, .percent_encoded => |p| p,
    } else "";
    return UriResult{
        .scheme = _u.scheme,
        .host   = _host,
        .path   = _path,
        .query  = _query,
        .port   = if (_u.port) |p| @intCast(p) else 0,
    };
}
